# Base geometry module defining interfaces and abstract classes

interface IShape:
    def area(self) -> float: ...

    def describe(self) -> str: ...

@abstract
class Shape:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    @abstract
    def area(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return f"Shape at ({self.x}, {self.y})"

