# Concrete shape implementations

from geometry import Shape, IShape

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, x: float, y: float, width: float, height: float):
        super().__init__(x, y)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} - Rectangle {self.width} x {self.height}"

class Circle(Shape):
    radius: float

    def __init__(self, x: float, y: float, radius: float):
        super().__init__(x, y)
        self.radius = radius

    @override
    def area(self) -> float:
        # Using approximation of pi
        return 3.14159 * self.radius * self.radius

def total_area(shapes: list[IShape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def describe_all(shapes: list[IShape]) -> list[str]:
    descriptions: list[str] = []
    for shape in shapes:
        descriptions.append(shape.describe())
    return descriptions
